exports.seed = async function (knex) {
  for (const [id, langs] of Object.entries(DATA)) {
    const update = {};
    for (const [lang, fields] of Object.entries(langs)) {
      update[`name_${lang}`] = fields.name;
      update[`deity_${lang}`] = fields.deity;
      update[`characteristics_${lang}`] = fields.characteristics;
      update[`negative_traits_${lang}`] = fields.negative_traits;
      update[`health_issues_${lang}`] = fields.health_issues;
      update[`health_root_cause_${lang}`] = fields.health_root_cause;
      update[`health_guidance_${lang}`] = fields.health_guidance;
    }
    await knex('nakshatras').where({ id: Number(id) }).update(update);
  }
};
